 # C++17 线程安全单例模式实现

## 方案一：Meyer's Singleton（推荐）

这是 C++11 起最简洁、最安全的实现方式。

```cpp
#include <iostream>
#include <string>
#include <thread>
#include <vector>

// ============================================
// Meyer's Singleton - 最推荐的实现方式
// ============================================
class MeyersSingleton {
public:
    // 获取唯一实例（线程安全，C++11 起保证）
    static MeyersSingleton& getInstance() {
        // 局部静态变量：C++11 起，初始化是线程安全的
        static MeyersSingleton instance;
        return instance;
    }

    // 删除拷贝和移动
    MeyersSingleton(const MeyersSingleton&) = delete;
    MeyersSingleton& operator=(const MeyersSingleton&) = delete;
    MeyersSingleton(MeyersSingleton&&) = delete;
    MeyersSingleton& operator=(MeyersSingleton&&) = delete;

    // 业务方法
    void doSomething(const std::string& caller) {
        std::lock_guard<std::mutex> lock(mutex_);
        std::cout << "[" << caller << "] Instance: " << this 
                  << ", counter: " << ++counter_ << std::endl;
    }

    int getCounter() const { return counter_; }

private:
    MeyersSingleton() {
        std::cout << "MeyersSingleton constructed (lazy)\n";
        // 模拟耗时初始化
        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }
    ~MeyersSingleton() {
        std::cout << "MeyersSingleton destroyed\n";
    }

    mutable std::mutex mutex_;
    int counter_ = 0;
};
```

## 方案二：std::call_once 实现

适用于需要更复杂初始化控制的场景。

```cpp
#include <mutex>
#include <memory>

// ============================================
// std::call_once 实现 - 更灵活的控制
// ============================================
class CallOnceSingleton {
public:
    static CallOnceSingleton& getInstance() {
        // call_once 保证 init_flag_ 对应的函数只执行一次
        std::call_once(init_flag_, &CallOnceSingleton::init);
        return *instance_;
    }

    static void destroyInstance() {
        std::lock_guard<std::mutex> lock(mutex_);
        instance_.reset();
        // 注意：重置后需要重新设置 init_flag 才能再次创建（通常不需要）
    }

    // 删除拷贝和移动
    CallOnceSingleton(const CallOnceSingleton&) = delete;
    CallOnceSingleton& operator=(const CallOnceSingleton&) = delete;

    void doWork(const std::string& caller) {
        std::lock_guard<std::mutex> lock(mutex_);
        std::cout << "[" << caller << "] CallOnceSingleton working, instance: " << this << "\n";
    }

private:
    CallOnceSingleton() {
        std::cout << "CallOnceSingleton constructed\n";
    }
    ~CallOnceSingleton() {
        std::cout << "CallOnceSingleton destroyed\n";
    }

    // 初始化函数（只执行一次）
    static void init() {
        instance_.reset(new CallOnceSingleton());
    }

    // 关键成员：call_once 需要的标志
    static std::once_flag init_flag_;      // 确保 init() 只执行一次
    static std::unique_ptr<CallOnceSingleton> instance_;
    static std::mutex mutex_;               // 保护其他操作
};

// 静态成员定义
std::once_flag CallOnceSingleton::init_flag_;
std::unique_ptr<CallOnceSingleton> CallOnceSingleton::instance_;
std::mutex CallOnceSingleton::mutex_;
```

## 方案三：模板单例（通用复用）

```cpp
// ============================================
// 通用单例模板 - 可复用
// ============================================
template<typename T>
class Singleton {
public:
    // 完美转发参数给构造函数
    template<typename... Args>
    static T& getInstance(Args&&... args) {
        static T instance(std::forward<Args>(args)...);
        return instance;
    }

    Singleton(const Singleton&) = delete;
    Singleton& operator=(const Singleton&) = delete;

protected:
    Singleton() = default;
    ~Singleton() = default;
};

// 使用示例
class Database {
public:
    explicit Database(std::string connStr) 
        : connectionString_(std::move(connStr)) {
        std::cout << "DB connected: " << connectionString_ << "\n";
    }

    void query(const std::string& sql) {
        std::cout << "Executing: " << sql << "\n";
    }

private:
    std::string connectionString_;
};
